// ================================================================
// SCORING
// ================================================================
function calcScore(answers, questions) {
  let total = 0, maxTotal = 0;
  questions.forEach(q => {
    const max = Math.max(...q.opts.map(o => o.s));
    maxTotal += max;
    if (answers[q.id] !== undefined) total += answers[q.id].s;
  });
  return Math.round((total / maxTotal) * 100);
}
function scoreLabel(score) {
  if (score <= 20) return { label:'Biological Age Warrior 🌟', color:'#27AE60' };
  if (score <= 35) return { label:'Slow & Healthy Ager 💪', color:'#74C245' };
  if (score <= 50) return { label:'Average Ager 📊', color:'#F1C40F' };
  if (score <= 65) return { label:'Accelerated Ager ⚠️', color:'#E67E22' };
  return { label:'Rapid Ager 🚨 — Time to Act', color:'#C0392B' };
}
function dailyLabel(score) {
  if (score <= 20) return { label:'Exceptional Day! 🌟', color:'#27AE60' };
  if (score <= 35) return { label:'Great Day! 💪', color:'#74C245' };
  if (score <= 50) return { label:'Average Day 📊', color:'#F1C40F' };
  if (score <= 65) return { label:'Below Average Day 😐', color:'#E67E22' };
  return { label:"Tough Day 💙 — Tomorrow's a Fresh Start", color:'#8B5CF6' };
}
function scoreColor(score) {
  if (score <= 25) return '#27AE60';
  if (score <= 40) return '#74C245';
  if (score <= 55) return '#F1C40F';
  if (score <= 70) return '#E67E22';
  return '#C0392B';
}
function catScores(answers, questions) {
  const cats = {};
  questions.forEach(q => {
    if (!cats[q.cat]) cats[q.cat] = { total:0, max:0 };
    const max = Math.max(...q.opts.map(o => o.s));
    cats[q.cat].max += max;
    if (answers[q.id] !== undefined) cats[q.cat].total += answers[q.id].s;
  });
  const result = {};
  Object.keys(cats).forEach(cat => {
    result[cat] = cats[cat].max > 0 ? Math.round((cats[cat].total / cats[cat].max) * 100) : 0;
  });
  return result;
}

// ================================================================
// STORAGE
// ================================================================
function save(key, val) { try { localStorage.setItem('ra_' + key, JSON.stringify(val)); } catch(e){} }
function load(key, def) { try { const v = localStorage.getItem('ra_' + key); return v !== null ? JSON.parse(v) : def; } catch(e){ return def; } }
function todayKey() { return new Date().toISOString().split('T')[0]; }
function getDailyEntry(dateStr) { return load('day_' + dateStr, null); }
function saveDailyEntry(dateStr, data) { save('day_' + dateStr, data); }
function getDateRange(days) {
  const result = [];
  for (let i = days - 1; i >= 0; i--) {
    const d = new Date(); d.setDate(d.getDate() - i);
    result.push(d.toISOString().split('T')[0]);
  }
  return result;
}

// ================================================================
// HELPERS
// ================================================================
function getDailyQuote() { const day = Math.floor(Date.now() / 86400000); return QUOTES[day % QUOTES.length]; }
function getCurrentFact() { const slot = Math.floor(Date.now() / (1000 * 60 * 60 * 3)); return HEALTH_FACTS[slot % HEALTH_FACTS.length]; }
function getGreeting() { const h = new Date().getHours(); return h < 12 ? 'Good morning' : h < 17 ? 'Good afternoon' : 'Good evening'; }

// ================================================================
// ROUTER
// ================================================================
let state = { view:'home', surveyStep:0, surveyAnswers:{}, trackerStep:0, trackerAnswers:{}, reportTab:'week' };
function showView(name) {
  document.querySelectorAll('.view').forEach(v => v.classList.remove('active'));
  const el = document.getElementById('view-' + name);
  if (el) el.classList.add('active');
  state.view = name;
  updateNav();
  window.scrollTo({ top:0, behavior:'smooth' });
}
function updateNav() {
  const hasSurvey = load('survey_done', false);
  document.querySelectorAll('[data-view]').forEach(btn => {
    btn.classList.toggle('active', btn.dataset.view === state.view);
    if (btn.dataset.requires === 'survey') btn.style.display = hasSurvey ? '' : 'none';
  });
}

// ================================================================
// HOME
// ================================================================
function initHome() {
  const hasSurvey = load('survey_done', false);
  const qs = document.getElementById('quote-strip-text');
  if (qs) qs.textContent = '"' + getDailyQuote() + '"';
  const ctaBtn = document.getElementById('hero-cta');
  if (ctaBtn) {
    if (hasSurvey) {
      ctaBtn.textContent = '🌿 Go to My Dashboard';
      ctaBtn.onclick = () => { renderDashboard(); showView('dashboard'); };
    } else {
      ctaBtn.onclick = () => { startSurvey(); showView('survey'); };
    }
  }
}

// ================================================================
// SURVEY
// ================================================================
function startSurvey() { state.surveyStep = 0; state.surveyAnswers = {}; renderSurveyStep(); }
function renderSurveyStep() {
  const q = SURVEY_Q[state.surveyStep];
  const total = SURVEY_Q.length;
  const pct = Math.round((state.surveyStep / total) * 100);
  document.getElementById('survey-prog-fill').style.width = pct + '%';
  document.getElementById('survey-prog-text').textContent = 'Question ' + (state.surveyStep + 1) + ' of ' + total;
  document.getElementById('survey-prog-pct').textContent = pct + '% complete';
  const sel = state.surveyAnswers[q.id];
  document.getElementById('survey-q-body').innerHTML = `
    <div class="q-card">
      <div class="q-cat">${q.icon} ${q.cat}</div>
      <span class="q-icon">${q.icon}</span>
      <p class="q-text">${q.q}</p>
      <p class="q-tip">💡 ${q.tip}</p>
      <div class="opts" id="opts-grid"></div>
      <div class="q-nav">
        <span class="q-counter">${state.surveyStep + 1} / ${total}</span>
        <button class="btn btn-primary" id="q-next-btn" ${sel === undefined ? 'disabled' : ''}>${state.surveyStep < total - 1 ? 'Next →' : '🌿 See My Results'}</button>
      </div>
    </div>`;
  const grid = document.getElementById('opts-grid');
  q.opts.forEach((opt, i) => {
    const btn = document.createElement('button');
    btn.className = 'opt' + (sel && sel.i === i ? ' sel' : '');
    btn.innerHTML = `<span class="opt-emoji">${opt.e}</span><span>${opt.t}</span>`;
    btn.onclick = () => {
      state.surveyAnswers[q.id] = { s:opt.s, i, text:opt.t };
      document.querySelectorAll('#opts-grid .opt').forEach(b => b.classList.remove('sel'));
      btn.classList.add('sel');
      document.getElementById('q-next-btn').disabled = false;
    };
    grid.appendChild(btn);
  });
  document.getElementById('q-next-btn').onclick = () => {
    if (!state.surveyAnswers[q.id]) return;
    if (state.surveyStep < total - 1) { state.surveyStep++; renderSurveyStep(); }
    else completeSurvey();
  };
}
function completeSurvey() {
  const score = calcScore(state.surveyAnswers, SURVEY_Q);
  const cats = catScores(state.surveyAnswers, SURVEY_Q);
  save('survey_done', true); save('survey_answers', state.surveyAnswers);
  save('survey_score', score); save('survey_cats', cats);
  renderResults(score, cats, state.surveyAnswers);
  showView('results');
}

// ================================================================
// RESULTS
// ================================================================
function renderResults(score, cats, answers) {
  const { label, color } = scoreLabel(score);
  const C = 2 * Math.PI * 80;
  const offset = C - (score / 100) * C;
  document.getElementById('res-score-num').textContent = score;
  const badge = document.getElementById('res-score-badge');
  badge.textContent = label; badge.style.color = color;
  badge.style.background = color + '22'; badge.style.borderColor = color + '55';
  const fill = document.getElementById('score-circle-fill');
  fill.style.stroke = color; fill.style.strokeDasharray = C; fill.style.strokeDashoffset = C;
  setTimeout(() => { fill.style.strokeDashoffset = offset; }, 250);
  const catGrid = document.getElementById('res-cat-grid');
  catGrid.innerHTML = '';
  Object.entries(cats).forEach(([cat, pct]) => {
    const col = scoreColor(pct);
    const lbl = pct <= 30 ? 'Great' : pct <= 55 ? 'Okay' : 'Work On';
    const qi = SURVEY_Q.find(x => x.cat === cat);
    catGrid.innerHTML += `<div class="cat-card"><div class="cat-row"><span class="cat-name-lbl">${qi?qi.icon:'📊'} ${cat}</span><span class="cat-score-lbl" style="background:${col}">${lbl}</span></div><div class="cat-bar-track"><div class="cat-bar-fill" style="width:${pct}%;background:${col}"></div></div></div>`;
  });
  const goodList = document.getElementById('fb-good-list');
  const badList = document.getElementById('fb-bad-list');
  goodList.innerHTML = ''; badList.innerHTML = '';
  SURVEY_Q.forEach(q => {
    const ans = answers[q.id];
    if (!ans) return;
    if (ans.s <= 1) goodList.innerHTML += `<div class="fb-card good"><div class="fb-hdr"><span class="fb-ico">${q.icon}</span><span class="fb-qname">${q.cat}</span></div><p class="fb-txt">${q.fb.good}</p></div>`;
    else if (ans.s >= 3) badList.innerHTML += `<div class="fb-card ${ans.s===3?'warn':'bad'}"><div class="fb-hdr"><span class="fb-ico">${q.icon}</span><span class="fb-qname">${q.cat}</span></div><p class="fb-txt">${q.fb.bad}</p></div>`;
  });
  if (!goodList.innerHTML) goodList.innerHTML = '<p style="color:var(--text-light);padding:12px;font-style:italic">No top areas yet — but that\'s exactly what we\'re here to change!</p>';
  if (!badList.innerHTML) badList.innerHTML = '<p style="color:var(--text-light);padding:12px;font-style:italic">No major red flags! Keep maintaining your excellent habits.</p>';
}

// ================================================================
// DASHBOARD
// ================================================================
function renderDashboard() {
  document.getElementById('dash-greeting').textContent = getGreeting() + '! 🌿';
  document.getElementById('dash-title').textContent = 'Your Vitality Hub';
  document.getElementById('dash-quote').textContent = '"' + getDailyQuote() + '"';
  document.getElementById('dash-fact').textContent = getCurrentFact();
  const surveyScore = load('survey_score', null);
  const last7 = getDateRange(7).map(d => getDailyEntry(d)).filter(Boolean);
  const streak = calcStreak();
  const weekAvg = last7.length ? Math.round(last7.reduce((a,b) => a + b.score, 0) / last7.length) : null;
  document.getElementById('stat-streak').textContent = streak + (streak === 1 ? ' day' : ' days');
  document.getElementById('stat-avg').textContent = weekAvg !== null ? weekAvg : '—';
  document.getElementById('stat-base').textContent = surveyScore !== null ? surveyScore : '—';
  const doneToday = !!getDailyEntry(todayKey());
  const cc = document.getElementById('checkin-card');
  document.getElementById('cc-title').textContent = doneToday ? "✅ You've checked in today!" : "⚡ Start Today's Check-In";
  document.getElementById('cc-sub').textContent = doneToday ? "Great job. Come back tomorrow for your next check-in." : "Takes about 5 minutes. Your daily score awaits!";
  if (doneToday) { cc.classList.add('done'); cc.onclick = () => { const e = getDailyEntry(todayKey()); if(e){ renderDayResults(e.score,e.answers,todayKey()); showView('day-results'); } }; }
  else { cc.classList.remove('done'); cc.onclick = () => { startTracker(); showView('tracker'); }; }
  renderMiniChart();
}
function calcStreak() {
  let s = 0;
  for (let i = 0; i < 365; i++) {
    const d = new Date(); d.setDate(d.getDate() - i);
    if (getDailyEntry(d.toISOString().split('T')[0])) s++;
    else if (i > 0) break;
  }
  return s;
}
function renderMiniChart() {
  const wrap = document.getElementById('mini-chart-wrap');
  if (!wrap) return;
  const dates = getDateRange(14);
  const labels = dates.map(d => { const p=d.split('-'); return p[2]+'/'+p[1]; });
  const data = dates.map(d => { const e=getDailyEntry(d); return e?e.score:null; });
  if (data.every(v=>v===null)) { wrap.innerHTML='<p class="no-data-msg">📊 Your trend chart will appear here after a few check-ins.</p>'; return; }
  wrap.innerHTML = '<div class="chart-container"><canvas id="mini-chart"></canvas></div>';
  const ctx = document.getElementById('mini-chart');
  if (window._miniChart) window._miniChart.destroy();
  window._miniChart = new Chart(ctx, { type:'line', data:{ labels, datasets:[{ label:'Aging Speed Score', data, borderColor:'#52B788', backgroundColor:'rgba(82,183,136,.1)', borderWidth:2.5, pointBackgroundColor:data.map(v=>v!==null?scoreColor(v):'transparent'), pointRadius:5, tension:0.4, fill:true, spanGaps:true }] }, options:{ responsive:true, maintainAspectRatio:false, plugins:{legend:{display:false}}, scales:{ y:{min:0,max:100,grid:{color:'rgba(0,0,0,.05)'},ticks:{font:{size:11}}}, x:{grid:{display:false},ticks:{font:{size:10},maxTicksLimit:7}} } } });
}

// ================================================================
// TRACKER
// ================================================================
function startTracker() { state.trackerStep=0; state.trackerAnswers={}; renderTrackerStep(); }
function renderTrackerStep() {
  const q = DAILY_Q[state.trackerStep];
  const total = DAILY_Q.length;
  const pct = Math.round((state.trackerStep / total) * 100);
  document.getElementById('track-prog-fill').style.width = pct + '%';
  document.getElementById('track-prog-text').textContent = 'Question ' + (state.trackerStep+1) + ' of ' + total;
  document.getElementById('track-prog-pct').textContent = pct + '% complete';
  const sel = state.trackerAnswers[q.id];
  document.getElementById('tracker-q-body').innerHTML = `
    <div class="q-card">
      <div class="q-cat">${q.icon} ${q.cat}</div>
      <span class="q-icon">${q.icon}</span>
      <p class="q-text">${q.q}</p>
      <div class="opts" id="track-opts"></div>
      <div class="q-nav">
        <button class="btn btn-outline btn-sm" id="track-back" ${state.trackerStep===0?'disabled':''}>← Back</button>
        <span class="q-counter">${state.trackerStep+1} / ${total}</span>
        <button class="btn btn-primary" id="track-next" ${sel===undefined?'disabled':''}>${state.trackerStep<total-1?'Next →':'📊 See My Score'}</button>
      </div>
    </div>`;
  const grid = document.getElementById('track-opts');
  q.opts.forEach((opt,i) => {
    const btn = document.createElement('button');
    btn.className = 'opt' + (sel&&sel.i===i?' sel':'');
    btn.innerHTML = `<span class="opt-emoji">${opt.e}</span><span>${opt.t}</span>`;
    btn.onclick = () => { state.trackerAnswers[q.id]={s:opt.s,i,text:opt.t}; document.querySelectorAll('#track-opts .opt').forEach(b=>b.classList.remove('sel')); btn.classList.add('sel'); document.getElementById('track-next').disabled=false; };
    grid.appendChild(btn);
  });
  document.getElementById('track-back').onclick = () => { if(state.trackerStep>0){state.trackerStep--;renderTrackerStep();} };
  document.getElementById('track-next').onclick = () => { if(!state.trackerAnswers[q.id])return; if(state.trackerStep<total-1){state.trackerStep++;renderTrackerStep();}else completeTracker(); };
}
function completeTracker() {
  const score = calcScore(state.trackerAnswers, DAILY_Q);
  const cats = catScores(state.trackerAnswers, DAILY_Q);
  const today = todayKey();
  saveDailyEntry(today, { score, cats, answers:state.trackerAnswers, date:today });
  renderDayResults(score, state.trackerAnswers, today);
  showView('day-results');
}

// ================================================================
// DAY RESULTS
// ================================================================
function renderDayResults(score, answers, dateStr) {
  const { label, color } = dailyLabel(score);
  const C = 2 * Math.PI * 80;
  const d = new Date(dateStr + 'T12:00:00');
  document.getElementById('dr-date').textContent = d.toLocaleDateString('en-US',{weekday:'long',year:'numeric',month:'long',day:'numeric'});
  document.getElementById('dr-score-num').textContent = score;
  const badge = document.getElementById('dr-score-badge');
  badge.textContent = label; badge.style.color = color; badge.style.borderColor = color + '55'; badge.style.background = color + '22';
  const fill = document.getElementById('dr-circle-fill');
  fill.style.stroke = color; fill.style.strokeDasharray = C; fill.style.strokeDashoffset = C;
  setTimeout(() => { fill.style.strokeDashoffset = C - (score/100)*C; }, 250);
  const fbList = document.getElementById('dr-feedback-list');
  fbList.innerHTML = '';
  DAILY_Q.forEach(q => {
    const ans = answers[q.id];
    if (!ans) return;
    const isGood = ans.s<=1, isBad = ans.s>=3;
    fbList.innerHTML += `<div class="day-feedback-card ${isGood?'great':isBad?'bad':'ok'}"><div class="fb-hdr"><span class="fb-ico">${q.icon}</span><span class="fb-qname">${q.cat} — ${ans.text}</span></div><p class="fb-txt">${isGood?q.advice.good:isBad?q.advice.bad:'Keeping it steady — small improvements here will compound over time.'}</p></div>`;
  });
}

// ================================================================
// REPORTS
// ================================================================
function renderReports(tab) {
  state.reportTab = tab || state.reportTab;
  document.querySelectorAll('.tab-btn').forEach(b => b.classList.toggle('active', b.dataset.tab===state.reportTab));
  const days = state.reportTab==='week'?7:state.reportTab==='month'?30:365;
  const entries = getDateRange(days).map(d=>({date:d,entry:getDailyEntry(d)})).filter(x=>x.entry);
  if (!entries.length) {
    document.getElementById('rep-chart-wrap').innerHTML = '<p class="no-data-msg" style="padding:60px 0">📊 No data yet for this period. Complete daily check-ins to see your reports here!</p>';
    document.getElementById('rep-stats-grid').innerHTML = '';
    document.getElementById('rep-cat-breakdown').innerHTML = '';
    return;
  }
  const scores = entries.map(e=>e.entry.score);
  const avg = Math.round(scores.reduce((a,b)=>a+b,0)/scores.length);
  const best = Math.min(...scores), worst = Math.max(...scores);
  document.getElementById('rep-stats-grid').innerHTML = `
    <div class="stat-c"><div class="stat-ic">📅</div><div class="stat-val">${entries.length}</div><div class="stat-lbl">Days Tracked</div></div>
    <div class="stat-c"><div class="stat-ic">📊</div><div class="stat-val" style="color:${scoreColor(avg)}">${avg}</div><div class="stat-lbl">Average Score</div></div>
    <div class="stat-c"><div class="stat-ic">🌟</div><div class="stat-val" style="color:${scoreColor(best)}">${best}</div><div class="stat-lbl">Best Day</div></div>
    <div class="stat-c"><div class="stat-ic">😓</div><div class="stat-val" style="color:${scoreColor(worst)}">${worst}</div><div class="stat-lbl">Toughest Day</div></div>`;
  const dates = getDateRange(days);
  const labels = dates.map(d=>{const p=d.split('-');return p[2]+'/'+p[1];});
  const data = dates.map(d=>{const e=getDailyEntry(d);return e?e.score:null;});
  document.getElementById('rep-chart-wrap').innerHTML = '<div class="chart-container" style="height:280px"><canvas id="rep-chart"></canvas></div>';
  if (window._repChart) window._repChart.destroy();
  window._repChart = new Chart(document.getElementById('rep-chart'),{ type:'line', data:{ labels, datasets:[{ label:'Score', data, borderColor:'#2D6A4F', backgroundColor:'rgba(45,106,79,.08)', borderWidth:2.5, pointBackgroundColor:data.map(v=>v?scoreColor(v):'transparent'), pointRadius:state.reportTab==='year'?3:5, tension:0.4, fill:true, spanGaps:true }] }, options:{ responsive:true, maintainAspectRatio:false, plugins:{legend:{display:false}}, scales:{ y:{min:0,max:100,grid:{color:'rgba(0,0,0,.04)'}}, x:{grid:{display:false},ticks:{maxTicksLimit:10}} } } });
  const allCats = {};
  entries.forEach(({entry}) => { Object.entries(entry.cats||{}).forEach(([cat,s]) => { if(!allCats[cat])allCats[cat]=[]; allCats[cat].push(s); }); });
  document.getElementById('rep-cat-breakdown').innerHTML = Object.entries(allCats).map(([cat,scores])=>{ const a=Math.round(scores.reduce((x,y)=>x+y,0)/scores.length); const col=scoreColor(a); const qi=DAILY_Q.find(x=>x.cat===cat); return `<div class="cat-card" style="margin-bottom:10px"><div class="cat-row"><span class="cat-name-lbl">${qi?qi.icon:'📊'} ${cat}</span><span class="cat-score-lbl" style="background:${col}">${a}/100</span></div><div class="cat-bar-track"><div class="cat-bar-fill" style="width:${a}%;background:${col}"></div></div></div>`; }).sort().join('');
}

// ================================================================
// AREAS
// ================================================================
function renderAreas() {
  const entries = getDateRange(30).map(d=>getDailyEntry(d)).filter(Boolean);
  const body = document.getElementById('areas-body-content');
  if (entries.length < 3) { body.innerHTML = '<p class="no-data-msg" style="text-align:center;padding:60px 0;font-style:italic;color:var(--text-light)">📊 Complete at least 3 daily check-ins to unlock your personalized Areas to Work On.</p>'; return; }
  const allCats = {};
  entries.forEach(e => { Object.entries(e.cats||{}).forEach(([cat,s])=>{ if(!allCats[cat])allCats[cat]=[]; allCats[cat].push(s); }); });
  const sorted = Object.entries(allCats).map(([cat,scores])=>({cat,avg:Math.round(scores.reduce((a,b)=>a+b,0)/scores.length)})).sort((a,b)=>b.avg-a.avg);
  body.innerHTML = sorted.map(({cat,avg},i)=>{ const adv=AREA_ADVICE[cat]; if(!adv)return''; const col=scoreColor(avg); const cls=avg>60?'c1':avg>40?'c2':'c3'; return `<div class="area-card ${cls}"><div class="area-hdr"><div class="area-name">${adv.icon} ${cat}</div><span class="area-badge" style="background:${col}">${avg}/100</span></div><p class="area-desc">${adv.desc}</p><ul class="area-tips">${adv.tips.map(t=>`<li>${t}</li>`).join('')}</ul><div class="ad-wrap"><div class="ad-unit ad-unit-inline">Advertisement</div></div></div>`; }).join('');
}

// ================================================================
// INIT
// ================================================================
document.addEventListener('DOMContentLoaded', () => {
  const hasSurvey = load('survey_done', false);
  document.querySelectorAll('[data-view]').forEach(el => {
    el.addEventListener('click', () => {
      const v = el.dataset.view;
      if (v==='dashboard') { renderDashboard(); showView('dashboard'); }
      else if (v==='tracker') { startTracker(); showView('tracker'); }
      else if (v==='reports') { renderReports('week'); showView('reports'); }
      else if (v==='areas') { renderAreas(); showView('areas'); }
      else showView(v);
    });
  });
  document.querySelectorAll('.tab-btn').forEach(btn => { btn.addEventListener('click', ()=>renderReports(btn.dataset.tab)); });
  initHome();
  if (hasSurvey) { renderDashboard(); showView('dashboard'); }
  else showView('home');
  updateNav();
});
